#include <bits/stdc++.h>
using namespace std;

int ask(vector<vector<bool>> &grid, vector<pair<int, int>> arr, int op) {
    int ans = 0;
    if(op==0) ans=1;
    for (auto [a, b]: arr) {
        if(op) ans=ans||grid[a][b];
        else ans=ans&&grid[a][b];
    }
    return ans;
}

void ans(bool x) {
    cout << x << endl;
}

int find_row(vector<vector<bool>> &grid, int need, int n) {
    int lo = 1, hi = n;
    int fin = 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        vector<pair<int, int>> qr;
        for (int i = 1; i <= mid; i++) qr.push_back({i, 1});
        if (need == ask(grid, qr, need)) {
            fin = mid;
            hi = mid-1;
        } 
        else lo = mid+1;
    }
    return fin;
}

int find_col(vector<vector<bool>> &grid, int need, int n) {
    int lo = 1, hi = n;
    int fin = 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        vector<pair<int, int>> qr;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= mid; j++) {
                qr.push_back({i, j});
            }
        }
        if (need == ask(grid, qr, need)) {
            fin = mid;
            hi = mid-1;
        }
        else lo = mid+1;
    }
    return fin;
}

void send_grid() {
    int n; cin >> n;
    bool ans; cin >> ans;
    vector<vector<bool>> grid(n+1, vector<bool>(n+1));
    for(int i = 0; i < n; i++) {
        string s;
        cin >> s;
        for(int j = 0; j < n; j++) if(s[j]=='1') grid[i+1][j+1]=1;
    }
    vector<pair<int, int>> qr;
    for (int i = 1; i <= n; i++) {
        qr.push_back({i, 1});
    }
    int o = ask(grid, qr, 1), a = ask(grid, qr, 0);
    int col, row;
    if (o == 1 && a == 0) {
        col = 1;
        row = find_row(grid, !ans, n);
    }
    else if (o == 0) {
        row = 1;
        if (ans == 0) col = 1;
        else col = find_col(grid, 1, n);
    }
    else {
        row = 1;
        if (ans == 1) col = 1;
        else col = find_col(grid, 0, n);
    }
    cout << row << " " << col << endl; 
}

void receive_grid() {
    int n; cin >> n;
    string row,col;
    cin >> row >> col;
    bool diff = false;
    for (int i = 0; i < n; i++) {
        if (col[i] != row[0]) diff = true;
    }
    if (diff) {
        ans(!(row[0]=='1'));
    }
    else {
        ans((row[0]=='1'));
    }
}

void solve() {
    string run; cin >> run;
    int t; cin >> t;
    if (run == "first") for (int i = 1; i <= t; i++) send_grid();
    else for (int i = 1; i <= t; i++) receive_grid();
}

int main() {
    int t = 1;
    while (t--) solve();
    return 0;
}

